import{_ as e,o as i,c as l,ai as r}from"./chunks/framework.CsYGeNYI.js";const f=JSON.parse('{"title":"功能","description":"","frontmatter":{"read_when":["你想了解 OpenSoul 支持的完整功能列表"],"summary":"OpenSoul 在渠道、路由、媒体和用户体验方面的功能。","title":"功能","x-i18n":{"generated_at":"2026-02-04T17:53:22Z","model":"claude-opus-4-5","provider":"pi","source_hash":"1b6aee0bfda751824cb6b3a99080b4c80c00ffb355a96f9cff1b596d55d15ed4","source_path":"concepts/features.md","workflow":15}},"headers":[],"relativePath":"zh-CN/concepts/features.md","filePath":"zh-CN/concepts/features.md","lastUpdated":1771906665000}'),t={name:"zh-CN/concepts/features.md"};function s(d,a,h,o,c,n){return i(),l("div",null,[...a[0]||(a[0]=[r('<h2 id="亮点" tabindex="-1"><a class="header-anchor" href="#亮点">#</a> 亮点</h2><h3 id="_30-渠道" tabindex="-1"><a class="header-anchor" href="#_30-渠道">#</a> 30+ 渠道</h3><p>通过单个 Gateway 网关支持 WhatsApp、Telegram、Discord、Slack、iMessage、Signal、Matrix 等。</p><h3 id="_50-技能" tabindex="-1"><a class="header-anchor" href="#_50-技能">#</a> 50+ 技能</h3><p>GitHub、Notion、Obsidian、Canvas、1Password 及可扩展插件 SDK。</p><h3 id="多智能体路由" tabindex="-1"><a class="header-anchor" href="#多智能体路由">#</a> 多智能体路由</h3><p>按智能体、工作区或发送者隔离会话。</p><h3 id="媒体" tabindex="-1"><a class="header-anchor" href="#媒体">#</a> 媒体</h3><p>支持图片、音频和文档的收发。</p><h3 id="跨平台应用" tabindex="-1"><a class="header-anchor" href="#跨平台应用">#</a> 跨平台应用</h3><p>Web 控制界面、macOS、Windows、iOS、Android、CLI/TUI。</p><h3 id="移动节点" tabindex="-1"><a class="header-anchor" href="#移动节点">#</a> 移动节点</h3><p>iOS 和 Android 节点，支持 Canvas。</p><h2 id="完整列表" tabindex="-1"><a class="header-anchor" href="#完整列表">#</a> 完整列表</h2><h3 id="渠道-30" tabindex="-1"><a class="header-anchor" href="#渠道-30">#</a> 渠道（30+）</h3><ul><li>WhatsApp（Baileys）、Telegram（grammY）、Discord、Slack、Signal、iMessage（BlueBubbles）</li><li>Mattermost、Matrix、LINE、Zalo、飞书、Google Chat、Microsoft Teams（插件）</li><li>Nextcloud Talk、Nostr、Twitch、WebChat、REST API、WebSocket</li></ul><h3 id="智能体核心" tabindex="-1"><a class="header-anchor" href="#智能体核心">#</a> 智能体核心</h3><ul><li>Pi 智能体 RPC 模式，支持工具流式传输</li><li>多模型支持：OpenAI、Anthropic、AWS Bedrock、Ollama（本地）等</li><li>记忆系统，支持向量搜索（LanceDB）</li><li>多智能体路由，按工作区或发送者隔离会话</li><li>Anthropic 和 OpenAI 的 OAuth 订阅认证</li><li>会话：私信合并为共享的 <code>main</code>；群组相互隔离</li><li>群聊支持，通过提及激活</li><li>长响应的流式传输和分块处理</li></ul><h3 id="媒体与语音" tabindex="-1"><a class="header-anchor" href="#媒体与语音">#</a> 媒体与语音</h3><ul><li>图片、音频和文档的收发</li><li>可选的语音消息转录</li><li>Voice Call 扩展，支持 TTS/STT</li></ul><h3 id="应用与界面" tabindex="-1"><a class="header-anchor" href="#应用与界面">#</a> 应用与界面</h3><ul><li>Web 控制界面和 WebChat</li><li>macOS 菜单栏应用</li><li>Windows 原生桌面应用（WPF）</li><li>iOS 和 Android 节点，支持配对和 Canvas</li><li>CLI 和 TUI，面向高级用户</li></ul><blockquote><p><strong>注意：</strong> 旧版 Claude、Codex、Gemini 和 Opencode 路径已被移除。Pi 是唯一的编程智能体路径。</p></blockquote>',23)])])}const u=e(t,[["render",s]]);export{f as __pageData,u as default};
